import java.util.ArrayList;
import java.util.List;

class Solution {
    public void generateStrings(int n, StringBuilder current, List<String> strings) {
        if (n == 0) {
            strings.add(current.toString());
            return;
        }
        for (char c = 'a'; c <= 'c'; ++c) {
            if (current.length() == 0 || current.charAt(current.length() - 1) != c) {
                current.append(c);
                generateStrings(n - 1, current, strings);
                current.deleteCharAt(current.length() - 1);
            }
        }
    }

    public String getHappyString(int n, int k) {
        List<String> strings = new ArrayList<>();
        StringBuilder current = new StringBuilder();
        generateStrings(n, current, strings);
        return k <= strings.size() ? strings.get(k - 1) : "";
    }
}
```

